from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad
import base64

def decrypt_str_data(encrypted_str, key):
    encrypted_bytes = base64.b64decode(encrypted_str)
    
    iv = encrypted_bytes[:16]  # Extract IV (first 16 bytes)
    cipher_text = encrypted_bytes[16:]  # Extract ciphertext

    cipher = AES.new(key, AES.MODE_CBC, iv)
    decrypted = unpad(cipher.decrypt(cipher_text), AES.block_size)

    return decrypted.decode('utf-8')

# Example usage:
# key should be 16, 24, or 32 bytes long
key = b'kYp3s6v9y$B&E)H+MbQeThWmZq4t7w!z'  # Example 16-byte key
